        analyticsQueue.async { [weak self] in
            guard let self = self else { return }
            
            var logMessage = "[AUTH] Event: \(event.rawValue)"
            
            if let identifier = userIdentifier {
                let hashedID = self.hashValue(identifier)
                logMessage += " | UserHash: \(hashedID)"
            }
            
            logMessage += " | SessionID: \(self.sessionID)"
            logMessage += " | Timestamp: \(Date().timeIntervalSince1970)"
            
            if self.isDebugMode {
                print(logMessage)
            }
            
            self.writeToSecureLog(logMessage)
        }
    }
    
