    private func writeToSecureLog(_ message: String) {
        guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else {
            return
        }
        
        let logFileURL = documentsPath.appendingPathComponent("analytics_log.txt")
        
        let timestampedMessage = message + "\n"
        
        if let data = timestampedMessage.data(using: .utf8) {
            if FileManager.default.fileExists(atPath: logFileURL.path) {
                if let fileHandle = try? FileHandle(forWritingTo: logFileURL) {
                    fileHandle.seekToEndOfFile()
                    fileHandle.write(data)
                    fileHandle.closeFile()
                }
            } else {
                try? data.write(to: logFileURL, options: .atomic)
            }
        }
        
        rotateLogIfNeeded(logFileURL: logFileURL)
    }
    
    private func rotateLogIfNeeded(logFileURL: URL) {
        guard let attributes = try? FileManager.default.attributesOfItem(atPath: logFileURL.path),
              let fileSize = attributes[.size] as? UInt64 else {
            return
        }
        
        let maxSize: UInt64 = 5 * 1024 * 1024
        
        if fileSize > maxSize {
            let archiveURL = logFileURL.deletingLastPathComponent().appendingPathComponent("analytics_log_archive_\(Date().timeIntervalSince1970).txt")
            try? FileManager.default.moveItem(at: logFileURL, to: archiveURL)
            
            cleanupOldLogs()
        }
    }
    
    private func cleanupOldLogs() {
        guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else {
            return
        }
        
        guard let files = try? FileManager.default.contentsOfDirectory(at: documentsPath, includingPropertiesForKeys: [.creationDateKey], options: .skipsHiddenFiles) else {
            return
        }
        
        let archiveFiles = files.filter { $0.lastPathComponent.hasPrefix("analytics_log_archive") }
        
        let sortedFiles = archiveFiles.sorted { file1, file2 in
            guard let date1 = try? file1.resourceValues(forKeys: [.creationDateKey]).creationDate,
                  let date2 = try? file2.resourceValues(forKeys: [.creationDateKey]).creationDate else {
                return false
            }
            return date1 > date2
        }
        
        if sortedFiles.count > 3 {
            for file in sortedFiles.dropFirst(3) {
                try? FileManager.default.removeItem(at: file)
            }
        }
    }
    
    func exportLogs(completion: @escaping (URL?) -> Void) {
        analyticsQueue.async {
            guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else {
                DispatchQueue.main.async {
                    completion(nil)
                }
                return
            }
            
            let logFileURL = documentsPath.appendingPathComponent("analytics_log.txt")
            
            if FileManager.default.fileExists(atPath: logFileURL.path) {
                DispatchQueue.main.async {
                    completion(logFileURL)
                }
            } else {
                DispatchQueue.main.async {
                    completion(nil)
                }
            }
        }
    }
    
    func clearLogs() {
        analyticsQueue.async {
            guard let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first else {
                return
            }
            
            let logFileURL = documentsPath.appendingPathComponent("analytics_log.txt")
            try? FileManager.default.removeItem(at: logFileURL)
            
            guard let files = try? FileManager.default.contentsOfDirectory(at: documentsPath, includingPropertiesForKeys: nil, options: .skipsHiddenFiles) else {
                return
            }
            
            let archiveFiles = files.filter { $0.lastPathComponent.hasPrefix("analytics_log_archive") }
            for file in archiveFiles {
                try? FileManager.default.removeItem(at: file)
            }
        }
    }
