final class SecureNetworkLogger {
    static let shared = SecureNetworkLogger()
    
    private init() {}
    
    func logRequest(url: URL, method: String, headers: [String: String]? = nil) {
        let sanitizedHeaders = sanitizeHeaders(headers)
        
        SecureAnalyticsManager.shared.logAPICall(
            endpoint: url.path,
            method: method
        )
        
        #if DEBUG
        print("[NETWORK_REQUEST] URL: \(url.absoluteString) | Method: \(method) | Headers: \(sanitizedHeaders)")
        #endif
    }
    
    func logResponse(url: URL, statusCode: Int, duration: TimeInterval, error: Error? = nil) {
        SecureAnalyticsManager.shared.logAPICall(
            endpoint: url.path,
            method: "RESPONSE",
            statusCode: statusCode,
            duration: duration
        )
        
        if let error = error {
            SecureAnalyticsManager.shared.logError(
                error: error,
                context: "API Response - \(url.path)",
                severity: statusCode >= 500 ? .high : .medium
            )
        }
        
        #if DEBUG
        print("[NETWORK_RESPONSE] URL: \(url.absoluteString) | Status: \(statusCode) | Duration: \(String(format: "%.3f", duration))s")
        #endif
    }
    
    private func sanitizeHeaders(_ headers: [String: String]?) -> [String: String] {
        guard let headers = headers else { return [:] }
        
        var sanitized: [String: String] = [:]
        let sensitiveKeys = ["authorization", "x-api-key", "x-auth-token", "cookie", "set-cookie"]
        
        for (key, value) in headers {
            if sensitiveKeys.contains(key.lowercased()) {
                sanitized[key] = "***REDACTED***"
            } else {
                sanitized[key] = value
            }
        }
        
        return sanitized
    }
}

