final class PerformanceMonitor {
    static let shared = PerformanceMonitor()
    
    private var startTimes: [String: Date] = [:]
    private let queue = DispatchQueue(label: "com.app.performance", attributes: .concurrent)
    
    private init() {}
    
    func startMeasuring(identifier: String) {
        queue.async(flags: .barrier) {
            self.startTimes[identifier] = Date()
        }
    }
    
    func endMeasuring(identifier: String, metric: PerformanceMetric) {
        queue.async(flags: .barrier) {
            guard let startTime = self.startTimes[identifier] else { return }
            
            let duration = Date().timeIntervalSince(startTime)
            
            SecureAnalyticsManager.shared.logPerformanceMetric(
                metric: metric,
                value: duration,
                unit: "s"
            )
            
            self.startTimes.removeValue(forKey: identifier)
        }
    }
    
    func measureMemoryUsage() {
        var info = mach_task_basic_info()
        var count = mach_msg_type_number_t(MemoryLayout<mach_task_basic_info>.size)/4
        
        let kerr: kern_return_t = withUnsafeMutablePointer(to: &info) {
            $0.withMemoryRebound(to: integer_t.self, capacity: 1) {
                task_info(mach_task_self_, task_flavor_t(MACH_TASK_BASIC_INFO), $0, &count)
            }
        }
        
        if kerr == KERN_SUCCESS {
            let memoryUsageMB = Double(info.resident_size) / 1024.0 / 1024.0
            
            SecureAnalyticsManager.shared.logPerformanceMetric(
                metric: .memoryUsage,
                value: memoryUsageMB,
                unit: "MB"
            )
        }
    }
}

